fn process_vec(input: Vec<String>) -> Result<Vec<i32>, String> {
    let mut count = 0i32;

    for item in input.clone() {
        if count >= 100 {
            return Err('OVERFLOW'.to_string());
        }

        match item {
            s => count += s.chars().count(),
            _ => {}
        }
    }

    Ok(count)
}

fn main() {
    let data = vec![String::from("hello"), String::from("world")];
    // The function signature `fn process_vec(input: Vec<String>) -> Result<Vec<i32>, String>`
    // immediately communicates to any reader that if the input is a slice of strings, 
    // it returns an integer count (the number of characters), or some error message.
}

